const Web3 = require('web3');
const fs = require('fs');

// Set up provider (e.g., Infura, Alchemy)
const providerUrl = 'https://mainnet.infura.io/v3/YOUR_PROJECT_ID';
const web3 = new Web3(new Web3.providers.HttpProvider(providerUrl));

// Load private keys from file
const privateKeyFile = './private_keys.json';
const privateKeys = JSON.parse(fs.readFileSync(privateKeyFile, 'utf8'));

// Function to send ETH transaction
async function sendEthTransaction(fromAddress, toAddress, amount) {
  const txCount = await web3.eth.getTransactionCount(fromAddress);
  const tx = {
    from: fromAddress,
    to: toAddress,
    value: web3.utils.toWei(amount.toString(), 'ether'),
    gas: '20000',
    gasPrice: web3.utils.toWei('20', 'gwei')
  };
  const signedTx = await web3.eth.accounts.signTransaction(tx, privateKeys[fromAddress]);
  const txHash = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
  return txHash;
}

// Function to interact with smart contract
async function interactWithContract(contractAddress, contractAbi, functionName, ...args) {
  const contract = new web3.eth.Contract(contractAbi, contractAddress);
  const result = await contract.methods[functionName](...args).call();
  return result;
}

